class Solution:
    def numberOfAlternatingGroups(self, colors, k: int) -> int:
        n = len(colors)
        doubled = colors + colors
        count = 0
        run = 1
        for i in range(1, n + k - 1):
            if doubled[i] != doubled[i - 1]:
                run += 1
            else:
                run = 1
            if i >= k - 1 and run >= k:
                count += 1
        return count

