var numberOfAlternatingGroups = function(colors, k) {
    const n = colors.length;
    const doubled = colors.concat(colors);
    let run = 1, count = 0;
    for (let i = 1; i < n + k - 1; i++) {
        if (doubled[i] !== doubled[i - 1]) {
            run++;
        } else {
            run = 1;
        }
        if (i >= k - 1 && run >= k) count++;
    }
    return count;
};
